#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

// Simple dynamic bitset for up to 40000 variables + RHS
typedef struct {
    uint64_t *bits;
    int size; // number of 64‑bit words
} Bitset;

static inline Bitset new_bitset(int nbits) {
    Bitset b;
    b.size = (nbits + 63) / 64;
    b.bits = (uint64_t*)calloc(b.size, sizeof(uint64_t));
    return b;
}
static inline void set_bit(Bitset *b, int pos) {
    b->bits[pos>>6] |= 1ULL << (pos & 63);
}
static inline int get_bit(const Bitset *b, int pos) {
    return (b->bits[pos>>6] >> (pos & 63)) & 1U;
}
static inline void xor_into(Bitset *dest, const Bitset *src) {
    for (int i=0;i<dest->size;i++) dest->bits[i] ^= src->bits[i];
}
static inline void free_bitset(Bitset *b) { free(b->bits); }

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        char line[205];
        int total = N*N;
        int *faulty = (int*)calloc(total, sizeof(int));
        int *init = (int*)calloc(total, sizeof(int));
        for(int i=0;i<N;i++){
            scanf("%s",line);
            for(int j=0;j<N;j++) init[i*N+j] = line[j]-'0';
        }
        for(int f=0;f<K;f++){
            int r,c; scanf("%d %d",&r,&c); r--;c--; faulty[r*N+c]=1;
        }
        // Map each pressable cell to a variable index
        int *varIdx = (int*)malloc(total*sizeof(int));
        int varCnt=0;
        for(int i=0;i<total;i++) if(!faulty[i]) varIdx[i]=varCnt++;
        // Build augmented matrix: rows = total equations, cols = varCnt + 1 (RHS)
        int cols = varCnt + 1;
        Bitset *mat = (Bitset*)malloc(total*sizeof(Bitset));
        for(int eq=0; eq<total; ++eq){
            mat[eq] = new_bitset(cols);
            // RHS = initial state
            if(init[eq]) set_bit(&mat[eq], varCnt); // last bit is RHS
            int r = eq / N, c = eq % N;
            // self
            if(!faulty[eq]) set_bit(&mat[eq], varIdx[eq]);
            // up
            if(r>0){int nb = (r-1)*N + c; if(!faulty[nb]) set_bit(&mat[eq], varIdx[nb]);}
            // down
            if(r+1<N){int nb = (r+1)*N + c; if(!faulty[nb]) set_bit(&mat[eq], varIdx[nb]);}
            // left
            if(c>0){int nb = r*N + (c-1); if(!faulty[nb]) set_bit(&mat[eq], varIdx[nb]);}
            // right
            if(c+1<N){int nb = r*N + (c+1); if(!faulty[nb]) set_bit(&mat[eq], varIdx[nb]);}
        }
        // Gaussian elimination over GF(2)
        int row=0, col=0;
        int rank=0;
        for(col=0; col<varCnt && row<total; ++col){
            int sel = -1;
            for(int i=row;i<total;i++) if(get_bit(&mat[i], col)){ sel=i; break; }
            if(sel==-1) continue; // no pivot in this column
            // swap rows
            Bitset tmp = mat[row]; mat[row]=mat[sel]; mat[sel]=tmp;
            // eliminate below
            for(int i=row+1;i<total;i++) if(get_bit(&mat[i], col)) xor_into(&mat[i], &mat[row]);
            ++row; ++rank;
        }
        // check for inconsistency
        int possible = 1;
        for(int i=rank;i<total;i++){
            // if all variable bits are 0 but RHS is 1 -> impossible
            int allZero = 1;
            for(int w=0; w<mat[i].size-1; ++w){ if(mat[i].bits[w]){ allZero=0; break; } }
            if(allZero && get_bit(&mat[i], varCnt)) { possible=0; break; }
        }
        printf(possible?"YES\n":"NO\n");
        // free
        for(int i=0;i<total;i++) free_bitset(&mat[i]);
        free(mat); free(varIdx); free(faulty); free(init);
    }
    return 0;
}

